var openWindows, window2;


openWindows = 0;
var window2_list = items.getItem('gWindows').members;
for (var window2_index in window2_list) {
  window2 = window2_list[window2_index];
  if (window2.state == 'OPEN') {
    openWindows = openWindows + 1;
  }
}
items.getItem('ScriptDemo').postUpdate(('Hello from Blockly! Open windows: ' + String(openWindows)));

var room, itemName, groupMember, roomName, currentTemperature, temperatureSetpoint;

// Describe this function...
function has_window(room) {
  if (room == 'Child1') {
    return true;
  }
  if (room == 'Child2') {
    return true;
  }
  if (room == 'Guestroom') {
    return true;
  }
  if (room == 'Kitchen') {
    return true;
  }
  if (room == 'LivingRoom') {
    return true;
  }
  if (room == 'Bedroom') {
    return true;
  }
  if (room == 'Office') {
    return true;
  }
  return false;
}

// Describe this function...
function get_room_name(itemName) {
  return itemName.slice(0, (itemName.indexOf('_') + 1) - 1);
}


var groupMember_list = items.getItem('gHeating').members;
for (var groupMember_index in groupMember_list) {
  groupMember = groupMember_list[groupMember_index];
  roomName = get_room_name(groupMember.name);
  currentTemperature = items.getItem(groupMember.name.replaceAll('_Heating','_Temperature'));
  temperatureSetpoint = items.getItem(groupMember.name.replaceAll('_Heating','_TemperatureSet'));
  if (has_window(roomName)) {
    if (items.getItem((String(roomName) + '_Window_Contact')).state == 'OPEN') {
      if (groupMember.state == 'ON') {
        console.info(('Window open, stop heating: ' + String(roomName)));
        groupMember.sendCommand('OFF');
      }
      continue;
    }
  }
  if (currentTemperature.quantityState.lessThan(temperatureSetpoint.quantityState)) {
    if (groupMember.state == 'OFF') {
      console.info(('Temperature too low, start heating: ' + String(roomName)));
      groupMember.sendCommand('ON');
    }
  } else {
    if (groupMember.state == 'ON') {
      console.info(('Temperature too high, stop heating: ' + String(roomName)));
      groupMember.sendCommand('OFF');
    }
  }
}
var groupMember_list2 = items.getItem('gAC').members;
for (var groupMember_index2 in groupMember_list2) {
  groupMember = groupMember_list2[groupMember_index2];
  roomName = get_room_name(groupMember.name);
  currentTemperature = items.getItem(groupMember.name.replaceAll('_AC','_Temperature'));
  temperatureSetpoint = items.getItem(groupMember.name.replaceAll('_AC','_TemperatureSet'));
  if (has_window(roomName)) {
    if (items.getItem((String(roomName) + '_Window_Contact')).state == 'OPEN') {
      if (groupMember.state == 'ON') {
        console.info(('Window open, stop air conditioning: ' + String(roomName)));
        groupMember.sendCommand('OFF');
      }
      continue;
    }
  }
  if (currentTemperature.quantityState.greaterThan(temperatureSetpoint.quantityState)) {
    if (groupMember.state == 'OFF') {
      console.info(('Temperature too high, start air conditioning: ' + String(roomName)));
      groupMember.sendCommand('ON');
    }
  } else {
    if (groupMember.state == 'ON') {
      console.info(('Temperature too low, stop air conditioning: ' + String(roomName)));
      groupMember.sendCommand('OFF');
    }
  }
}
